proof:
-- By definition of `bits2num_e`, we know that `(bits2num_e args).eval = bits2num args`.
have h_bits2num_e : (bits2num_e args).eval = bits2num args := by
  -- By induction on the array k, we can show that the foldl operation on the array k, when evaluated, is equal to the foldl operation on the same array but with the elements converted to their ZMod p values.
  have h_ind : ∀ (k : Array (ZMod p)), (Array.foldl (fun acc b => Exp.v b + Exp.c 2 * acc) (Exp.c 0) k 0 k.size).eval = (Array.foldl (fun acc b => b + 2 * acc) 0 k 0 k.size) := by
    intro k; induction k using Array.recOn ; simp +decide [ * ] ;
    induction ‹List ( ZMod p ) › using List.reverseRecOn <;> aesop;
  aesop;
exact if_neg ( sub_ne_zero_of_ne <| h_bits2num_e.symm ▸ h.symm )

